#include <bits/stdc++.h>
using namespace std;
const int maxn=1e5+5;
string a,b[maxn];
int l,s[maxn];
int main(){
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	getline(cin,a);
	for(int i=0;i<a.size();i++){
		if(a[i]!=' '){
			b[l]+=a[i];
			s++;
		}else{
			l++;
			a[l]=max(s[l-1],s[l-2]);
		}
	}
	cout<<a[0]<<"\n"<<a[l];
	return 0;
}
